package tn.esprit.controllers;

import javafx.fxml.FXML;
import javafx.geometry.Pos;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.Separator;
import javafx.scene.image.Image;
import javafx.scene.image.ImageView;
import javafx.scene.layout.*;
import tn.esprit.entities.Commande;
import tn.esprit.entities.CommandeProduit;
import tn.esprit.services.CommandeService;

import java.io.File;
import java.util.List;

public class CommandeController {

    @FXML
    private FlowPane commandeContainer;

    private final CommandeService service = new CommandeService();

    @FXML
    public void initialize() {
        loadCommandes();
    }

    private void loadCommandes() {
        List<Commande> commandes = service.recuperer();
        commandeContainer.getChildren().clear();
        for (Commande c : commandes) {
            VBox card = createCommandeCard(c);
            commandeContainer.getChildren().add(card);
        }
    }

    private VBox createCommandeCard(Commande c) {
        VBox card = new VBox(0);
        card.getStyleClass().add("cmd-card");

        // ── TOP SECTION ──
        VBox topSection = new VBox(10);
        topSection.getStyleClass().add("card-top");

        // Header: titre + badge statut
        HBox header = new HBox();
        header.setAlignment(Pos.CENTER_LEFT);

        HBox titleBox = new HBox(8);
        titleBox.setAlignment(Pos.CENTER_LEFT);
        Label titleIcon = new Label("");
        titleIcon.getStyleClass().add("card-title-icon");
        Label title = new Label("Commande #" + c.getId_commande());
        title.getStyleClass().add("card-title");
        titleBox.getChildren().addAll(titleIcon, title);

        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);

        Label status = new Label(c.getStatut_commande().toUpperCase());
        status.getStyleClass().addAll("badge", getBadgeClass(c.getStatut_commande()));

        header.getChildren().addAll(titleBox, spacer, status);

        // Date
        Label date = new Label("  " + c.getDate_creation_commande().toString());
        date.getStyleClass().add("card-date");

        // Séparateur
        Separator sep = new Separator();
        sep.getStyleClass().add("card-sep");

        // Label "PRODUITS"
        Label prodsLabel = new Label("PRODUITS");
        prodsLabel.getStyleClass().add("products-label");

        // Images produits côte à côte (toutes affichées, sans limite)
        HBox imagesBox = new HBox(8);
        imagesBox.setAlignment(Pos.CENTER_LEFT);

        List<CommandeProduit> produits = c.getCommande_produits();
        for (CommandeProduit cp : produits) {
            try {
                String path = cp.getProduit().getImage_produit();
                StackPane imgWrap = new StackPane();

                if (path != null && !path.isEmpty()) {
                    File file = new File(path);
                    if (file.exists()) {
                        ImageView img = new ImageView(new Image(file.toURI().toString()));
                        img.setFitWidth(52);
                        img.setFitHeight(52);
                        img.setPreserveRatio(false);
                        imgWrap.getStyleClass().add("product-img-wrap");
                        imgWrap.getChildren().add(img);
                    } else {
                        imgWrap.getStyleClass().add("product-img-placeholder");
                        imgWrap.getChildren().add(new Label(""));
                    }
                } else {
                    imgWrap.getStyleClass().add("product-img-placeholder");
                    imgWrap.getChildren().add(new Label(""));
                }

                imagesBox.getChildren().add(imgWrap);

            } catch (Exception e) {
                StackPane ph = new StackPane(new Label(""));
                ph.getStyleClass().add("product-img-placeholder");
                imagesBox.getChildren().add(ph);
            }
        }

        topSection.getChildren().addAll(header, date, sep, prodsLabel, imagesBox);

        // ── BOTTOM SECTION ──
        VBox bottomSection = new VBox(8);
        bottomSection.getStyleClass().add("card-bottom");

        // Total
        HBox totalRow = new HBox();
        totalRow.setAlignment(Pos.CENTER_LEFT);
        Label totalLabel = new Label("Total");
        totalLabel.getStyleClass().add("total-label");
        Region totalSpacer = new Region();
        HBox.setHgrow(totalSpacer, Priority.ALWAYS);
        Label total = new Label(String.format("%.2f Dt", c.getMontant_total_cents()));
        total.getStyleClass().add("cmd-total");
        totalRow.getChildren().addAll(totalLabel, totalSpacer, total);

        // Bouton Facture PDF (pleine largeur)
        Button btnFacture = new Button("⬇  Facture PDF");
        btnFacture.getStyleClass().add("btn-primary");
        btnFacture.setMaxWidth(Double.MAX_VALUE);
        btnFacture.setOnAction(e -> handleFacturePDF(c));

        // Boutons Suivi + Détails (grille 50/50)
        HBox btnGrid = new HBox(8);
        Button btnSuivi = new Button("  Suivi livraison");
        btnSuivi.getStyleClass().add("btn-secondary");
        btnSuivi.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(btnSuivi, Priority.ALWAYS);
        btnSuivi.setOnAction(e -> handleSuiviLivraison(c));

        Button btnDetails = new Button("  Voir les détails");
        btnDetails.getStyleClass().add("btn-secondary");
        btnDetails.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(btnDetails, Priority.ALWAYS);
        btnDetails.setOnAction(e -> handleVoirDetails(c));

        btnGrid.getChildren().addAll(btnSuivi, btnDetails);

        bottomSection.getChildren().addAll(totalRow, btnFacture, btnGrid);

        card.getChildren().addAll(topSection, bottomSection);
        return card;
    }

    // ── Handlers (à implémenter selon votre logique) ──

    private void handleFacturePDF(Commande c) {
        // TODO: générer et ouvrir la facture PDF
        System.out.println("Facture PDF pour commande #" + c.getId_commande());
    }

    private void handleSuiviLivraison(Commande c) {
        // TODO: ouvrir la vue suivi livraison
        System.out.println("Suivi livraison pour commande #" + c.getId_commande());
    }

    private void handleVoirDetails(Commande c) {
        // TODO: ouvrir la vue détails commande
        System.out.println("Détails pour commande #" + c.getId_commande());
    }

    // ── Utilitaire badge CSS ──

    private String getBadgeClass(String statut) {
        if (statut == null) return "badge-default";
        statut = statut.toLowerCase();
        if (statut.contains("livraison")) return "badge-livraison";
        if (statut.contains("cours"))     return "badge-cours";
        if (statut.contains("final"))     return "badge-finalise";
        return "badge-default";
    }
}

package tn.esprit.controllers;

import javafx.fxml.FXML;
import javafx.geometry.Pos;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.Separator;
import javafx.scene.image.Image;
import javafx.scene.image.ImageView;
import javafx.scene.layout.*;
import tn.esprit.entities.Commande;
import tn.esprit.entities.CommandeProduit;
import tn.esprit.services.CommandeService;

import java.io.File;
import java.util.List;

public class CommandeController {

    @FXML
    private FlowPane commandeContainer;

    private final CommandeService service = new CommandeService();

    @FXML
    public void initialize() {
        loadCommandes();
    }

    private void loadCommandes() {
        List<Commande> commandes = service.recuperer();
        commandeContainer.getChildren().clear();
        for (Commande c : commandes) {
            VBox card = createCommandeCard(c);
            commandeContainer.getChildren().add(card);
        }
    }

    private VBox createCommandeCard(Commande c) {
        VBox card = new VBox(0);
        card.getStyleClass().add("cmd-card");

        // ── TOP SECTION ──
        VBox topSection = new VBox(10);
        topSection.getStyleClass().add("card-top");

        // Header: titre + badge statut
        HBox header = new HBox();
        header.setAlignment(Pos.CENTER_LEFT);

        HBox titleBox = new HBox(8);
        titleBox.setAlignment(Pos.CENTER_LEFT);
        Label titleIcon = new Label("");
        titleIcon.getStyleClass().add("card-title-icon");
        Label title = new Label("Commande #" + c.getId_commande());
        title.getStyleClass().add("card-title");
        titleBox.getChildren().addAll(titleIcon, title);

        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);

        Label status = new Label(c.getStatut_commande().toUpperCase());
        status.getStyleClass().addAll("badge", getBadgeClass(c.getStatut_commande()));

        header.getChildren().addAll(titleBox, spacer, status);

        // Date
        Label date = new Label("  " + c.getDate_creation_commande().toString());
        date.getStyleClass().add("card-date");

        // Séparateur
        Separator sep = new Separator();
        sep.getStyleClass().add("card-sep");

        // Label "PRODUITS"
        Label prodsLabel = new Label("PRODUITS");
        prodsLabel.getStyleClass().add("products-label");

        // Images produits côte à côte (toutes affichées, sans limite)
        HBox imagesBox = new HBox(8);
        imagesBox.setAlignment(Pos.CENTER_LEFT);

        List<CommandeProduit> produits = c.getCommande_produits();
        for (CommandeProduit cp : produits) {
            try {
                String path = cp.getProduit().getImage_produit();
                StackPane imgWrap = new StackPane();

                if (path != null && !path.isEmpty()) {
                    File file = new File(path);
                    if (file.exists()) {
                        ImageView img = new ImageView(new Image(file.toURI().toString()));
                        img.setFitWidth(52);
                        img.setFitHeight(52);
                        img.setPreserveRatio(false);
                        imgWrap.getStyleClass().add("product-img-wrap");
                        imgWrap.getChildren().add(img);
                    } else {
                        imgWrap.getStyleClass().add("product-img-placeholder");
                        imgWrap.getChildren().add(new Label(""));
                    }
                } else {
                    imgWrap.getStyleClass().add("product-img-placeholder");
                    imgWrap.getChildren().add(new Label(""));
                }

                imagesBox.getChildren().add(imgWrap);

            } catch (Exception e) {
                StackPane ph = new StackPane(new Label(""));
                ph.getStyleClass().add("product-img-placeholder");
                imagesBox.getChildren().add(ph);
            }
        }

        topSection.getChildren().addAll(header, date, sep, prodsLabel, imagesBox);

        // ── BOTTOM SECTION ──
        VBox bottomSection = new VBox(8);
        bottomSection.getStyleClass().add("card-bottom");

        // Total
        HBox totalRow = new HBox();
        totalRow.setAlignment(Pos.CENTER_LEFT);
        Label totalLabel = new Label("Total");
        totalLabel.getStyleClass().add("total-label");
        Region totalSpacer = new Region();
        HBox.setHgrow(totalSpacer, Priority.ALWAYS);
        double montant = c.getMontant_total_cents() / 100.0;
        Label total = new Label(String.format("%.2f Dt", montant));
        total.getStyleClass().add("cmd-total");
        totalRow.getChildren().addAll(totalLabel, totalSpacer, total);

        // Bouton Facture PDF (pleine largeur)
        Button btnFacture = new Button("⬇  Facture PDF");
        btnFacture.getStyleClass().add("btn-primary");
        btnFacture.setMaxWidth(Double.MAX_VALUE);
        btnFacture.setOnAction(e -> handleFacturePDF(c));

        // Boutons Suivi + Détails (grille 50/50)
        HBox btnGrid = new HBox(8);
        Button btnSuivi = new Button("  Suivi livraison");
        btnSuivi.getStyleClass().add("btn-secondary");
        btnSuivi.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(btnSuivi, Priority.ALWAYS);
        btnSuivi.setOnAction(e -> handleSuiviLivraison(c));

        Button btnDetails = new Button("  Voir les détails");
        btnDetails.getStyleClass().add("btn-secondary");
        btnDetails.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(btnDetails, Priority.ALWAYS);
        btnDetails.setOnAction(e -> handleVoirDetails(c));

        btnGrid.getChildren().addAll(btnSuivi, btnDetails);

        bottomSection.getChildren().addAll(totalRow, btnFacture, btnGrid);

        card.getChildren().addAll(topSection, bottomSection);
        return card;
    }

    // ── Handlers (à implémenter selon votre logique) ──

    private void handleFacturePDF(Commande c) {
        // TODO: générer et ouvrir la facture PDF
        System.out.println("Facture PDF pour commande #" + c.getId_commande());
    }

    private void handleSuiviLivraison(Commande c) {
        // TODO: ouvrir la vue suivi livraison
        System.out.println("Suivi livraison pour commande #" + c.getId_commande());
    }

    private void handleVoirDetails(Commande c) {
        // TODO: ouvrir la vue détails commande
        System.out.println("Détails pour commande #" + c.getId_commande());
    }

    // ── Utilitaire badge CSS ──

    private String getBadgeClass(String statut) {
        if (statut == null) return "badge-default";
        statut = statut.toLowerCase();
        if (statut.contains("livraison")) return "badge-livraison";
        if (statut.contains("cours"))     return "badge-cours";
        if (statut.contains("final"))     return "badge-finalise";
        return "badge-default";
    }
}

package tn.esprit.mains;

import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.stage.Stage;

public class MainProduitFx extends Application {

    @Override
    public void start(Stage primaryStage) throws Exception {
        // Charger le fichier FXML
        FXMLLoader loader = new FXMLLoader(getClass().getResource("/ajouterProduit.fxml"));
        Parent root = loader.load();

        // Créer la scène
        Scene scene = new Scene(root, 500, 600);

        // Configurer la fenêtre
        primaryStage.setTitle("Gestion des Produits - MedFlow");
        primaryStage.setScene(scene);
        primaryStage.setResizable(true);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

package tn.esprit.mains;

import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.stage.Stage;

public class MainProduitFx extends Application {

    @Override
    public void start(Stage primaryStage) throws Exception {
        try {
            // Charger le fichier FXML
            FXMLLoader loader = new FXMLLoader(getClass().getResource("/ajouterProduit.fxml"));
            Parent root = loader.load();

            // Créer la scène
            Scene scene = new Scene(root, 500, 600);

            // Configurer la fenêtre
            primaryStage.setTitle("Gestion des Produits - MedFlow");
            primaryStage.setScene(scene);
            primaryStage.setResizable(true);
            primaryStage.show();
        } catch (Exception e) {
            e.printStackTrace();
            System.err.println("Erreur au chargement de l'interface FXML : " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        launch(args);
    }
}

/* ═══════════════════════════════════════════════════
   COMMANDE_DETAIL.CSS  –  Pharmacie · Détail Commande
   ═══════════════════════════════════════════════════ */

.detail-root   { -fx-background-color: #f0fdf9; }
.detail-scroll { -fx-background-color: #f0fdf9; -fx-background: #f0fdf9; }
.detail-main   { -fx-background-color: #f0fdf9; }

/* ══════════════════════════════════════════
   HEADER CARD  (gradient teal)
   ══════════════════════════════════════════ */
.detail-header-card {
    -fx-background-color: linear-gradient(to right, #0d9488, #0891b2);
    -fx-background-radius: 20;
    -fx-padding: 22 28 22 28;
    -fx-effect: dropshadow(gaussian, rgba(13,148,136,0.35), 22, 0, 0, 6);
}

.detail-order-icon {
    -fx-background-color: rgba(255,255,255,0.18);
    -fx-background-radius: 14;
    -fx-padding: 10;
    -fx-font-size: 20px;
}

.detail-order-num {
    -fx-font-size: 20px;
    -fx-font-weight: bold;
    -fx-text-fill: white;
}

.detail-order-date {
    -fx-font-size: 12px;
    -fx-text-fill: rgba(255,255,255,0.78);
}

.detail-status-pill {
    -fx-padding: 5 16;
    -fx-background-radius: 20;
    -fx-font-size: 11.5px;
    -fx-font-weight: bold;
}

/* ══════════════════════════════════════════
   SECTION CARDS
   ══════════════════════════════════════════ */
.section-card {
    -fx-background-color: white;
    -fx-background-radius: 18;
    -fx-effect: dropshadow(gaussian, rgba(0,0,0,0.06), 16, 0, 0, 3);
    -fx-border-color: rgba(0,0,0,0.06);
    -fx-border-radius: 18;
    -fx-border-width: 0.5;
    -fx-padding: 20 24 20 24;
}

.section-title {
    -fx-font-size: 14px;
    -fx-font-weight: bold;
    -fx-text-fill: #111827;
}

.section-icon {
    -fx-background-color: #f0fdf9;
    -fx-background-radius: 8;
    -fx-padding: 5;
    -fx-font-size: 14px;
}

.section-sep { -fx-opacity: 0.35; -fx-padding: 2 0; }

/* ── Table header row ── */
.table-header-row {
    -fx-background-color: #f9fafb;
    -fx-background-radius: 10;
    -fx-padding: 8 12;
}
.table-header-lbl {
    -fx-font-size: 11px;
    -fx-font-weight: bold;
    -fx-text-fill: #9ca3af;
}

/* ── Product row ── */
.product-row {
    -fx-padding: 10 12;
    -fx-background-radius: 12;
}
.product-row:hover { -fx-background-color: #f9fafb; }

.product-name {
    -fx-font-size: 14px;
    -fx-font-weight: bold;
    -fx-text-fill: #111827;
}
.product-cat {
    -fx-font-size: 11.5px;
    -fx-text-fill: #9ca3af;
}

.qty-badge {
    -fx-background-color: #0d9488;
    -fx-background-radius: 20;
    -fx-text-fill: white;
    -fx-font-size: 11px;
    -fx-font-weight: bold;
    -fx-padding: 3 10;
    -fx-min-width: 30;
    -fx-alignment: center;
}

.price-lbl      { -fx-font-size: 13px; -fx-text-fill: #374151; }
.subtotal-lbl   { -fx-font-size: 13.5px; -fx-font-weight: bold; -fx-text-fill: #0d9488; }

/* ── Total row ── */
.total-row-wrap {
    -fx-background-color: #f0fdf9;
    -fx-background-radius: 12;
    -fx-padding: 12 16;
    -fx-border-color: #ccfbf1;
    -fx-border-radius: 12;
    -fx-border-width: 1;
}
.total-row-lbl { -fx-font-size: 14px; -fx-font-weight: bold; -fx-text-fill: #374151; }
.total-row-val { -fx-font-size: 22px; -fx-font-weight: bold; -fx-text-fill: #0d9488; }

/* ══════════════════════════════════════════
   INFO LIVRAISON / RÉSUMÉ
   ══════════════════════════════════════════ */
.info-label {
    -fx-font-size: 11px;
    -fx-text-fill: #9ca3af;
    -fx-font-weight: bold;
}
.info-value {
    -fx-font-size: 13.5px;
    -fx-text-fill: #111827;
}
.info-value-empty { -fx-text-fill: #d1d5db; }

.resume-key   { -fx-font-size: 13px; -fx-text-fill: #6b7280; }
.resume-value { -fx-font-size: 13px; -fx-font-weight: bold; -fx-text-fill: #111827; }
.resume-value-teal { -fx-text-fill: #0d9488; }

.next-step-box {
    -fx-background-color: #f0fdf9;
    -fx-background-radius: 10;
    -fx-padding: 10 14;
    -fx-border-color: #99f6e4;
    -fx-border-radius: 10;
    -fx-border-width: 1;
}
.next-step-key { -fx-font-size: 11px; -fx-text-fill: #6b7280; -fx-font-weight: bold; }
.next-step-val { -fx-font-size: 13px; -fx-text-fill: #0f766e; -fx-font-weight: bold; }

/* ══════════════════════════════════════════
   BUTTONS
   ══════════════════════════════════════════ */
.btn-back {
    -fx-background-color: white;
    -fx-text-fill: #374151;
    -fx-background-radius: 12;
    -fx-border-color: #e5e7eb;
    -fx-border-radius: 12;
    -fx-border-width: 1;
    -fx-padding: 11 20;
    -fx-font-size: 13px;
    -fx-cursor: hand;
}
.btn-back:hover { -fx-background-color: #f9fafb; }

.btn-primary-detail {
    -fx-background-color: linear-gradient(to right, #0d9488, #0891b2);
    -fx-text-fill: white;
    -fx-background-radius: 12;
    -fx-padding: 11 22;
    -fx-font-size: 13px;
    -fx-font-weight: bold;
    -fx-effect: dropshadow(gaussian, rgba(13,148,136,0.28), 10, 0, 0, 3);
    -fx-cursor: hand;
}
.btn-primary-detail:hover {
    -fx-background-color: linear-gradient(to right, #0f766e, #0369a1);
}

.btn-download {
    -fx-background-color: linear-gradient(to right, #0d9488, #0891b2);
    -fx-text-fill: white;
    -fx-background-radius: 10;
    -fx-padding: 9 18;
    -fx-font-size: 12.5px;
    -fx-font-weight: bold;
    -fx-cursor: hand;
    -fx-effect: dropshadow(gaussian, rgba(13,148,136,0.25), 8, 0, 0, 2);
}
.btn-download:hover { -fx-background-color: linear-gradient(to right, #0f766e, #0369a1); }

/* badges */
.badge-detail { -fx-padding: 5 16; -fx-background-radius: 20; -fx-font-size: 11.5px; -fx-font-weight: bold; }
.badge-attente   { -fx-background-color: rgba(255,255,255,0.22); -fx-text-fill: white; -fx-border-color: rgba(255,255,255,0.4); -fx-border-radius: 20; -fx-border-width: 1; }
.badge-livraison { -fx-background-color: rgba(255,255,255,0.22); -fx-text-fill: white; -fx-border-color: rgba(255,255,255,0.4); -fx-border-radius: 20; -fx-border-width: 1; }
.badge-cours     { -fx-background-color: rgba(255,255,255,0.22); -fx-text-fill: white; -fx-border-color: rgba(255,255,255,0.4); -fx-border-radius: 20; -fx-border-width: 1; }
.badge-finalise  { -fx-background-color: rgba(255,255,255,0.22); -fx-text-fill: white; -fx-border-color: rgba(255,255,255,0.4); -fx-border-radius: 20; -fx-border-width: 1; }

/* ═══════════════════════════════════════════════════
   COMMANDE_DETAIL.CSS  –  Pharmacie · Détail Commande
   ═══════════════════════════════════════════════════ */

.detail-root   { -fx-background-color: #f0fdf9; }
.detail-scroll { -fx-background-color: #f0fdf9; -fx-background: #f0fdf9; }
.detail-main   { -fx-background-color: #f0fdf9; }

/* ══════════════════════════════════════════
   HEADER CARD  (gradient teal)
   ══════════════════════════════════════════ */
.detail-header-card {
    -fx-background-color: linear-gradient(to right, #2EC4C7, #2B9FA4);
    -fx-background-radius: 20;
    -fx-padding: 22 28 22 28;
    -fx-effect: dropshadow(gaussian, rgba(46,196,199,0.22), 22, 0, 0, 6);
}

.detail-order-icon {
    -fx-background-color: rgba(255,255,255,0.18);
    -fx-background-radius: 14;
    -fx-padding: 10;
    -fx-font-size: 20px;
}

.detail-order-num {
    -fx-font-size: 20px;
    -fx-font-weight: bold;
    -fx-text-fill: white;
}

.detail-order-date {
    -fx-font-size: 12px;
    -fx-text-fill: rgba(255,255,255,0.78);
}

.detail-status-pill {
    -fx-padding: 5 16;
    -fx-background-radius: 20;
    -fx-font-size: 11.5px;
    -fx-font-weight: bold;
}

/* ══════════════════════════════════════════
   SECTION CARDS
   ══════════════════════════════════════════ */
.section-card {
    -fx-background-color: white;
    -fx-background-radius: 18;
    -fx-effect: dropshadow(gaussian, rgba(0,0,0,0.06), 16, 0, 0, 3);
    -fx-border-color: rgba(0,0,0,0.06);
    -fx-border-radius: 18;
    -fx-border-width: 0.5;
    -fx-padding: 20 24 20 24;
}

.section-title {
    -fx-font-size: 14px;
    -fx-font-weight: bold;
    -fx-text-fill: #111827;
}

.section-icon {
    -fx-background-color: #f0fdf9;
    -fx-background-radius: 8;
    -fx-padding: 5;
    -fx-font-size: 14px;
}

.section-sep { -fx-opacity: 0.35; -fx-padding: 2 0; }

/* ── Table header row ── */
.table-header-row {
    -fx-background-color: #f9fafb;
    -fx-background-radius: 10;
    -fx-padding: 8 12;
}
.table-header-lbl {
    -fx-font-size: 11px;
    -fx-font-weight: bold;
    -fx-text-fill: #9ca3af;
}

/* ── Product row ── */
.product-row {
    -fx-padding: 10 12;
    -fx-background-radius: 12;
}
.product-row:hover { -fx-background-color: #f9fafb; }

.product-name {
    -fx-font-size: 14px;
    -fx-font-weight: bold;
    -fx-text-fill: #111827;
}
.product-cat {
    -fx-font-size: 11.5px;
    -fx-text-fill: #9ca3af;
}

.qty-badge {
    -fx-background-color: #0d9488;
    -fx-background-radius: 20;
    -fx-text-fill: white;
    -fx-font-size: 11px;
    -fx-font-weight: bold;
    -fx-padding: 3 10;
    -fx-min-width: 30;
    -fx-alignment: center;
}

.price-lbl      { -fx-font-size: 13px; -fx-text-fill: #374151; }
.subtotal-lbl   { -fx-font-size: 13.5px; -fx-font-weight: bold; -fx-text-fill: #0d9488; }

/* ── Total row ── */
.total-row-wrap {
    -fx-background-color: #f0fdf9;
    -fx-background-radius: 12;
    -fx-padding: 12 16;
    -fx-border-color: #ccfbf1;
    -fx-border-radius: 12;
    -fx-border-width: 1;
}
.total-row-lbl { -fx-font-size: 14px; -fx-font-weight: bold; -fx-text-fill: #374151; }
.total-row-val { -fx-font-size: 22px; -fx-font-weight: bold; -fx-text-fill: #0d9488; }

/* ══════════════════════════════════════════
   INFO LIVRAISON / RÉSUMÉ
   ══════════════════════════════════════════ */
.info-label {
    -fx-font-size: 11px;
    -fx-text-fill: #9ca3af;
    -fx-font-weight: bold;
}
.info-value {
    -fx-font-size: 13.5px;
    -fx-text-fill: #111827;
}
.info-value-empty { -fx-text-fill: #d1d5db; }

.resume-key   { -fx-font-size: 13px; -fx-text-fill: #6b7280; }
.resume-value { -fx-font-size: 13px; -fx-font-weight: bold; -fx-text-fill: #111827; }
.resume-value-teal { -fx-text-fill: #0d9488; }

.next-step-box {
    -fx-background-color: #f0fdf9;
    -fx-background-radius: 10;
    -fx-padding: 10 14;
    -fx-border-color: #99f6e4;
    -fx-border-radius: 10;
    -fx-border-width: 1;
}
.next-step-key { -fx-font-size: 11px; -fx-text-fill: #6b7280; -fx-font-weight: bold; }
.next-step-val { -fx-font-size: 13px; -fx-text-fill: #0f766e; -fx-font-weight: bold; }

/* ══════════════════════════════════════════
   BUTTONS
   ══════════════════════════════════════════ */
.btn-back {
    -fx-background-color: white;
    -fx-text-fill: #374151;
    -fx-background-radius: 12;
    -fx-border-color: #e5e7eb;
    -fx-border-radius: 12;
    -fx-border-width: 1;
    -fx-padding: 11 20;
    -fx-font-size: 13px;
    -fx-cursor: hand;
}
.btn-back:hover { -fx-background-color: #f9fafb; }

.btn-primary-detail {
    -fx-background-color: linear-gradient(to right, #2EC4C7, #2B9FA4);
    -fx-text-fill: white;
    -fx-background-radius: 12;
    -fx-padding: 11 22;
    -fx-font-size: 13px;
    -fx-font-weight: bold;
    -fx-effect: dropshadow(gaussian, rgba(13,148,136,0.28), 10, 0, 0, 3);
    -fx-cursor: hand;
}
.btn-primary-detail:hover {
    -fx-background-color: linear-gradient(to right, #2B9FA4, #2EC4C7);
}

.btn-download {
    -fx-background-color: linear-gradient(to right, #2EC4C7, #2B9FA4);
    -fx-text-fill: white;
    -fx-background-radius: 10;
    -fx-padding: 9 18;
    -fx-font-size: 12.5px;
    -fx-font-weight: bold;
    -fx-cursor: hand;
    -fx-effect: dropshadow(gaussian, rgba(13,148,136,0.25), 8, 0, 0, 2);
}
.btn-download:hover { -fx-background-color: linear-gradient(to right, #2B9FA4, #2EC4C7); }

/* badges */
.badge-detail {
    -fx-background-color: #2EC4C7;
    -fx-text-fill: white;
    -fx-border-radius: 20;
    -fx-background-radius: 20;
    -fx-font-weight: bold;
}
.badge-attente   { -fx-background-color: rgba(255,255,255,0.22); -fx-text-fill: white; -fx-border-color: rgba(255,255,255,0.4); -fx-border-radius: 20; -fx-border-width: 1; }
.badge-livraison { -fx-background-color: rgba(255,255,255,0.22); -fx-text-fill: white; -fx-border-color: rgba(255,255,255,0.4); -fx-border-radius: 20; -fx-border-width: 1; }
.badge-cours     { -fx-background-color: rgba(255,255,255,0.22); -fx-text-fill: white; -fx-border-color: rgba(255,255,255,0.4); -fx-border-radius: 20; -fx-border-width: 1; }
.badge-finalise  { -fx-background-color: rgba(255,255,255,0.22); -fx-text-fill: white; -fx-border-color: rgba(255,255,255,0.4); -fx-border-radius: 20; -fx-border-width: 1; }
